// GitServiceServer is the server API for GitService service.
// All implementations must embed UnimplementedGitServiceServer
// for forward compatibility.
//
// GitService is the single gRPC service exposed by CodeValdGit.
// All operations are scoped to the agency that owns this database instance.
// The agency_id is determined at server construction time and is not passed
// per-call (see CodeValdAI for the same pattern).
type GitServiceServer interface {
	// InitRepo creates a new Repository entity for this agency.
	// Error: ALREADY_EXISTS if a repository with the same name already exists.
	InitRepo(context.Context, *InitRepoRequest) (*Repository, error)
	// ListRepositories returns all Repository entities for this agency.
	ListRepositories(context.Context, *ListRepositoriesRequest) (*ListRepositoriesResponse, error)
	// GetRepository retrieves a Repository entity by its ID.
	// Error: NOT_FOUND if no repository with that ID exists.
	GetRepository(context.Context, *GetRepositoryRequest) (*Repository, error)
	// GetRepositoryByName retrieves a Repository entity by its human-readable name.
	// Error: NOT_FOUND if no repository with that name exists.
	GetRepositoryByName(context.Context, *GetRepositoryByNameRequest) (*Repository, error)
	// DeleteRepo marks the specified repository entity as archived (soft delete).
	// Error: NOT_FOUND if no repository with that ID exists.
	DeleteRepo(context.Context, *DeleteRepoRequest) (*DeleteRepoResponse, error)
	// PurgeRepo permanently removes all data for the specified repository.
	// Irreversible. Error: NOT_FOUND if no repository with that ID exists.
	PurgeRepo(context.Context, *PurgeRepoRequest) (*PurgeRepoResponse, error)
	// CreateBranch creates a new Branch entity from the specified source.
	// Error: ALREADY_EXISTS if a branch with the given name exists.
	// Error: NOT_FOUND if from_branch_id is non-empty and not found.
	CreateBranch(context.Context, *CreateBranchRequest) (*Branch, error)
	// GetBranch retrieves a Branch entity by its ID.
	// Error: NOT_FOUND if no branch with that ID exists.
	GetBranch(context.Context, *GetBranchRequest) (*Branch, error)
	// ListBranches returns all Branch entities for the specified repository.
	ListBranches(context.Context, *ListBranchesRequest) (*ListBranchesResponse, error)
	// DeleteBranch removes a Branch entity.
	// Error: NOT_FOUND if no branch with that ID exists.
	// Error: FAILED_PRECONDITION if branch is the repository default branch.
	DeleteBranch(context.Context, *DeleteBranchRequest) (*DeleteBranchResponse, error)
	// MergeBranch merges the given branch into the repository default branch.
	// Returns the updated default Branch on success.
	// Error: ABORTED with MergeConflictInfo detail on content conflict.
	// Error: NOT_FOUND if no branch with that ID exists.
	MergeBranch(context.Context, *MergeBranchRequest) (*Branch, error)
	// CreateTag creates an immutable Tag entity pointing to the specified commit.
	// Error: ALREADY_EXISTS if a tag with the given name exists.
	CreateTag(context.Context, *CreateTagRequest) (*Tag, error)
	// GetTag retrieves a Tag entity by its ID.
	// Error: NOT_FOUND if no tag with that ID exists.
	GetTag(context.Context, *GetTagRequest) (*Tag, error)
	// ListTags returns all Tag entities for the specified repository.
	ListTags(context.Context, *ListTagsRequest) (*ListTagsResponse, error)
	// DeleteTag removes a Tag entity.
	// Error: NOT_FOUND if no tag with that ID exists.
	DeleteTag(context.Context, *DeleteTagRequest) (*DeleteTagResponse, error)
	// WriteFile commits a file to the specified branch and returns the Commit
	// entity created by this write.
	// Error: NOT_FOUND if the branch does not exist.
	WriteFile(context.Context, *WriteFileRequest) (*Commit, error)
	// ReadFile retrieves the Blob entity for a file at the branch's current HEAD.
	// Error: NOT_FOUND if the branch or file path does not exist.
	ReadFile(context.Context, *ReadFileRequest) (*Blob, error)
	// DeleteFile removes a file from the specified branch as a new commit and
	// returns the deletion Commit entity.
	// Error: NOT_FOUND if the branch or file path does not exist.
	DeleteFile(context.Context, *DeleteFileRequest) (*Commit, error)
	// ListDirectory returns immediate children at the given path on the branch.
	// Error: NOT_FOUND if the branch or path does not exist.
	ListDirectory(context.Context, *ListDirectoryRequest) (*ListDirectoryResponse, error)
	// Log returns the commit history for the branch, newest first.
	// Optionally filtered to a specific file path and capped by limit.
	// Error: NOT_FOUND if the branch does not exist.
	Log(context.Context, *LogRequest) (*LogResponse, error)
	// Diff returns per-file change summaries between two refs.
	// Refs may be branch IDs or commit SHAs.
	// Error: NOT_FOUND if either ref cannot be resolved.
	Diff(context.Context, *DiffRequest) (*DiffResponse, error)
	// ImportRepo begins an async import of a public Git repository.
	// Returns immediately with a job ID; poll GetImportStatus for progress.
	// Error: ALREADY_EXISTS if a repository with the same name already exists.
	// Error: FAILED_PRECONDITION if an import is already in progress.
	ImportRepo(context.Context, *ImportRepoRequest) (*ImportRepoResponse, error)
	// GetImportStatus returns the current state of an import job.
	// Error: NOT_FOUND if no job with the given ID exists.
	GetImportStatus(context.Context, *GetImportStatusRequest) (*ImportJobResponse, error)
	// CancelImport cancels a pending or running import job.
	// Error: NOT_FOUND if no job with the given ID exists.
	// Error: FAILED_PRECONDITION if the job is already in a terminal state.
	CancelImport(context.Context, *CancelImportRequest) (*CancelImportResponse, error)
	// FetchBranch begins an async on-demand fetch for a previously imported
	// stub branch, materialising its full commit history and file tree.
	// Returns immediately with a FetchBranchJob; poll GetFetchBranchStatus for
	// progress.
	// Error: NOT_FOUND if the repository or branch does not exist.
	// Error: FAILED_PRECONDITION (ErrBranchAlreadyFetched) if the branch status
	// is already "fetched".
	FetchBranch(context.Context, *FetchBranchRequest) (*FetchBranchJob, error)
	// GetFetchBranchStatus returns the current state of a branch fetch job.
	// Error: NOT_FOUND if no job with the given ID exists.
	GetFetchBranchStatus(context.Context, *GetFetchBranchStatusRequest) (*FetchBranchJob, error)
	// CreateKeyword creates a new Keyword entity in the taxonomy.
	// Error: ALREADY_EXISTS if a keyword with the same name exists under the same parent.
	// Error: NOT_FOUND if parent_id is set and does not exist.
	CreateKeyword(context.Context, *CreateKeywordRequest) (*Keyword, error)
	// GetKeyword retrieves a Keyword entity by its ID.
	// Error: NOT_FOUND if no keyword with that ID exists.
	GetKeyword(context.Context, *GetKeywordRequest) (*Keyword, error)
	// ListKeywords returns Keyword entities matching the given filter.
	// When parent_id is empty, root keywords are returned.
	ListKeywords(context.Context, *ListKeywordsRequest) (*ListKeywordsResponse, error)
	// GetKeywordTree returns the full taxonomy subtree rooted at keyword_id,
	// or the full forest of root keywords when keyword_id is empty.
	GetKeywordTree(context.Context, *GetKeywordTreeRequest) (*GetKeywordTreeResponse, error)
	// UpdateKeyword updates mutable fields of a Keyword entity.
	// Error: NOT_FOUND if no keyword with that ID exists.
	UpdateKeyword(context.Context, *UpdateKeywordRequest) (*Keyword, error)
	// DeleteKeyword removes a Keyword entity and re-roots its children.
	// Error: NOT_FOUND if no keyword with that ID exists.
	DeleteKeyword(context.Context, *DeleteKeywordRequest) (*DeleteKeywordResponse, error)
	// CreateEdge creates a documentation edge between two entities on a branch.
	// Error: NOT_FOUND if the branch does not exist.
	// Error: INVALID_ARGUMENT if the relationship name is not a valid edge type.
	CreateEdge(context.Context, *CreateEdgeRequest) (*CreateEdgeResponse, error)
	// DeleteEdge removes a documentation edge between two entities on a branch.
	// Error: NOT_FOUND if the branch or edge does not exist.
	// Error: INVALID_ARGUMENT if the relationship name is invalid.
	DeleteEdge(context.Context, *DeleteEdgeRequest) (*DeleteEdgeResponse, error)
	// GetNeighborhood returns all entities and edges reachable from entity_id
	// within the given depth (1-3), bounded by a 100-node hard cap.
	// Error: NOT_FOUND if the branch or entity does not exist.
	GetNeighborhood(context.Context, *GetNeighborhoodRequest) (*GraphResult, error)
	// SearchByKeywords returns entities tagged with the specified keywords,
	// optionally cascading down the keyword hierarchy.
	// Error: NOT_FOUND if the branch does not exist.
	SearchByKeywords(context.Context, *SearchByKeywordsRequest) (*GraphResult, error)
	mustEmbedUnimplementedGitServiceServer()
}

